BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?depType ?otherElem ?otherName WHERE {
  ?execSoft vocab:NamedElement_name "Executive Software" .
  {
    ?dep rdf:type vocab:dependency .
    ?dep vocab:Dependency_client ?execSoft .
    ?dep vocab:Dependency_supplier ?otherElem .
    BIND("supplier" AS ?depType)
  }
  UNION
  {
    ?dep rdf:type vocab:dependency .
    ?dep vocab:Dependency_supplier ?execSoft .
    ?dep vocab:Dependency_client ?otherElem .
    BIND("client" AS ?depType)
  }
  OPTIONAL { ?otherElem vocab:NamedElement_name ?otherName }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?conn ?connName ?end1 ?end2 ?port1 ?port2 ?role1 ?role2 WHERE {
  ?conn rdf:type vocab:connector .
  ?conn vocab:Connector_end ?end1 .
  ?conn vocab:Connector_end ?end2 .
  ?end1 vocab:ConnectorEnd_role ?port1 .
  ?end2 vocab:ConnectorEnd_role ?port2 .
  FILTER(?end1 != ?end2)
  {
    ?port1 vocab:NamedElement_qualifiedName ?qname1 .
    FILTER(CONTAINS(?qname1, "Executive%20Software"))
    BIND(?port1 AS ?role1)
    BIND(?port2 AS ?role2)
  }
  UNION
  {
    ?port2 vocab:NamedElement_qualifiedName ?qname2 .
    FILTER(CONTAINS(?qname2, "Executive%20Software"))
    BIND(?port2 AS ?role1)
    BIND(?port1 AS ?role2)
  }
  OPTIONAL { ?conn vocab:NamedElement_name ?connName }
  OPTIONAL { ?port1 vocab:NamedElement_name ?name1 }
  OPTIONAL { ?port2 vocab:NamedElement_name ?name2 }
}
LIMIT 50

