BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?activity ?activityName ?edge ?source ?target WHERE {
  <http://api.koneksys.com/cameo/TMT/block/TMT::Project::Work%2520Packages::Project%2520Systems%2520Engineering::01%2520Components::Operational::TMT%2520Observatory%2520System::Conceptual%2520Design::Executive%2520Software> vocab:Element_ownedElement ?activity .
  ?activity rdf:type vocab:activity .
  OPTIONAL { ?activity vocab:NamedElement_name ?activityName }
  OPTIONAL {
    ?activity vocab:Activity_edge ?edge .
    OPTIONAL { ?edge vocab:ActivityEdge_source ?source }
    OPTIONAL { ?edge vocab:ActivityEdge_target ?target }
  }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT DISTINCT ?req ?reqName ?body WHERE {
  ?req rdf:type vocab:tmt%20requirement .
  ?req vocab:NamedElement_name ?reqName .
  FILTER(CONTAINS(LCASE(STR(?reqName)), LCASE("executive")))
  OPTIONAL { ?req vocab:Comment_body ?body }
}
LIMIT 30

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?activity ?activityName ?qname WHERE {
  ?activity rdf:type vocab:activity .
  ?activity vocab:NamedElement_name ?activityName .
  FILTER(CONTAINS(LCASE(STR(?activityName)), LCASE("executive")) || CONTAINS(LCASE(STR(?activityName)), LCASE("acquire")) || CONTAINS(LCASE(STR(?activityName)), LCASE("guide")))
  OPTIONAL { ?activity vocab:NamedElement_qualifiedName ?qname }
}
LIMIT 30
